import{_ as d,C as A,o as i,c as u,a0 as r,b as n,w as a,a as t,E as o,a1 as h,j as s}from"./chunks/framework.BjpW4enL.js";const y=JSON.parse('{"title":"Aegis-LLM","description":"","frontmatter":{},"headers":[],"relativePath":"projects/aegis-llm.md","filePath":"projects/aegis-llm.md"}'),c={name:"projects/aegis-llm.md"};function p(g,e,m,E,C,k){const l=A("Mermaid");return i(),u("div",null,[e[2]||(e[2]=r('<h1 id="aegis-llm" tabindex="-1">Aegis-LLM <a class="header-anchor" href="#aegis-llm" aria-label="Permalink to &quot;Aegis-LLM&quot;">​</a></h1><p>비용 절감과 인젝션 방어를 위한 엔터프라이즈 레벨의 LLM 보안 가드레일 프록시 엔진입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>Stable</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/aegis-llm" target="_blank" rel="noreferrer">GitHub (devcy0922/aegis-llm)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Rust</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>외부 LLM 공급자(OpenAI 등)를 직접 연동할 경우, 내부 직원의 실수나 외부 공격자의 프롬프트 인젝션(Prompt Injection) 시도로 인해 시스템 명령어 권한이 탈취되거나, 이메일/주민등록번호 등의 개인정보(PII)가 외부로 유출될 위험이 상존합니다. 또한 무제한적인 API 호출로 인한 오남용 비용 리스크가 큽니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>성능 오버헤드가 적은 Rust 언어를 사용해 API 경계면(Edge)에서 초고속으로 트래픽을 중계하며, 요청 전달 전에 인젝션 위협을 실시간 필터링하고 데이터 유출(DLP) 방지 및 API Key 기반 사용량 제한(Rate Limiting)을 단일 바이너리 내에서 효율적으로 수행하기 위해 구축했습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>프롬프트 인젝션 탐지 및 400 Bad Request 조기 차단</li><li>주민등록번호, 이메일, 평문 API Key 등의 PII 정보 감지 및 마스킹</li><li>API Key별 분당 요청 수(RPM) 제한 (Sliding Window 방식)</li><li>OpenAI Responses API 규격을 Chat Completions 규격으로 자동Adaptation 중계</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(i(),n(h,null,{default:a(()=>[o(l,{id:"mermaid-73",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20Client%5B%22Client%20(SDK%2FCLI)%22%5D%20--%3E%7CHTTPS%20Request%7C%20Aegis%5B%22Aegis-LLM%20Proxy%22%5D%0A%20%20%20%20subgraph%20Core%20%5B%22Aegis-LLM%20Pipeline%22%5D%0A%20%20%20%20%20%20%20%20Aegis%20--%3E%20Auth%5B%22Auth%20%26%20RateLimiter%20(auth.rs)%22%5D%0A%20%20%20%20%20%20%20%20Auth%20--%3E%20Safety%5B%22PII%20%26%20Injection%20Filter%20(security.rs)%22%5D%0A%20%20%20%20%20%20%20%20Safety%20--%3E%20Adapter%5B%22OpenAI%20Format%20Adapter%20(responses_adapter.rs)%22%5D%0A%20%20%20%20end%0A%20%20%20%20Adapter%20--%3E%7CClean%20Request%7C%20LLM%5B%22LLM%20Upstream%20(vLLM)%22%5D%0A%20%20%20%20Aegis%20-.-%3E%7CStream%20Output%7C%20Audit%5B%22Audit%20Log%20(audit.jsonl)%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=s("hr",null,null,-1)),e[4]||(e[4]=s("h2",{id:"_5-request-flow",tabindex:"-1"},[t("5. Request Flow "),s("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(i(),n(h,null,{default:a(()=>[o(l,{id:"mermaid-78",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Client%20as%20Client%0A%20%20%20%20participant%20Aegis%20as%20Aegis-LLM%0A%20%20%20%20participant%20Upstream%20as%20vLLM%20Upstream%0A%0A%20%20%20%20Client-%3E%3EAegis%3A%20POST%20%2Fv1%2Fchat%2Fcompletions%20(Prompt%20%2B%20API%20Key)%0A%20%20%20%20Aegis-%3E%3EAegis%3A%20API%20Key%20%EC%9C%A0%ED%9A%A8%EC%84%B1%20%EB%B0%8F%20RPM%20%ED%95%9C%EB%8F%84%20%EC%A1%B0%ED%9A%8C%0A%20%20%20%20alt%20RPM%20%ED%95%9C%EB%8F%84%20%EC%B4%88%EA%B3%BC%0A%20%20%20%20%20%20%20%20Aegis--%3E%3EClient%3A%20429%20Too%20Many%20Requests%0A%20%20%20%20end%0A%20%20%20%20Aegis-%3E%3EAegis%3A%20PII%20%EB%A7%88%EC%8A%A4%ED%82%B9%20%EB%B0%8F%20%ED%94%84%EB%A1%AC%ED%94%84%ED%8A%B8%20%EC%9D%B8%EC%A0%9D%EC%85%98%20%ED%82%A4%EC%9B%8C%EB%93%9C%20%EC%8A%A4%EC%BA%94%0A%20%20%20%20alt%20%EC%9D%B8%EC%A0%9D%EC%85%98%20%ED%83%90%EC%A7%80%0A%20%20%20%20%20%20%20%20Aegis--%3E%3EClient%3A%20400%20Bad%20Request%20(Blocked)%0A%20%20%20%20end%0A%20%20%20%20Aegis-%3E%3EUpstream%3A%20%EC%A0%84%EB%8B%AC%20(Adaptated%20payload)%0A%20%20%20%20Upstream--%3E%3EAegis%3A%20Response%0A%20%20%20%20Aegis-%3E%3EAegis%3A%20%EA%B0%90%EC%82%AC%EB%A1%9C%EA%B7%B8%20%EC%A0%81%EC%9E%AC%20(audit.jsonl)%0A%20%20%20%20Aegis--%3E%3EClient%3A%20200%20OK%20Response%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=r(`<hr><h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>정규식 배제 고속 스캔</strong>: 프롬프트 인젝션 1차 스캔 시 정규식(Regex)을 배제하고 <code>contains</code> 키워드 매칭(O(n·m))을 통해 지연율(latency) 증가를 2ms 이하로 극도로 제한했습니다.</li><li><strong>3-Tier 인증 아키텍처</strong>: static config, SurrealDB, JWT 토큰 방식을 단계별로 시도하여 대규모 실시간 요청 처리와 정적 로컬 시연 모두 안정적으로 지원합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>외부 위협 탐지 시 Upstream LLM으로 페이로드를 전달하지 않고 에지 단에서 즉시 커넥션을 차단하여 불필요한 LLM 추론 비용 소모와 프롬프트 전파를 원천 봉쇄합니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>실시간 Prometheus 텔레메트리 <code>/metrics</code> 엔드포인트를 제공하여 RPM 소비량, 차단 횟수, 레이턴시 분포를 관측 가능하게 제공합니다.</li><li>매 요청마다 UUID 기반의 <code>trace_id</code>를 부여해 <code>logs/audit.jsonl</code> 감사 로그에 비동기 플러시합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Framework</strong>: Rust (Axum, Tower-HTTP)</li><li><strong>Database</strong>: SurrealDB (Config caching &amp; API key store)</li><li><strong>Metrics</strong>: Prometheus</li></ul><hr><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>설정 파일 경로를 환경변수로 지정한 후 바이너리를 실행합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 가상 설정 파일 생성 및 실행</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GOVAIL_CONFIG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;configs/gateway.toml&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $GOVAIL_CONFIG</span></span></code></pre></div><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>정밀한 의미 기반 인젝션(Semantic Injection) 탐지를 위한 임베딩 분석 레이어가 아직 포함되지 않아, 키워드 우회 기법에 취약할 수 있습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>벡터 데이터베이스를 활용한 의미론적 유사도 기반 프롬프트 인젝션 방어 기법 도입.</li></ul>`,17))])}const _=d(c,[["render",p]]);export{y as __pageData,_ as default};
